import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");

        String name = scanner.nextLine();

        // Define a maximum buffer size
        int bufferSize = 10;

        if (name.length() > bufferSize) {
            System.out.println("Input string exceeds buffer size. Please enter a shorter name.");
            return;
        }

        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        // Copy input string into the fixed-size buffer with proper bounds checking
        name.getChars(0, Math.min(name.length(), bufferSize), buffer, 0);

        // Additional handling for names shorter than the buffer size
        for (int i = name.length(); i < bufferSize; i++) {
            buffer[i] = '\0'; // Null-terminate the buffer to prevent data leakage
